INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (2, 5, 'Week 5', '', 'The fifth week of fishing league saw 49 walleyes brought to the scale for 118.47 lbs.  Taking top honors was Logan Spray and Mikkal Erickson weighing in 5 fish for  17.98 lbs.  They also had the big fish of the night an 8.87 lber.  Second place went to Steve Dahle and Jamie Jahn with 5 fish for 15.88 lbs.  Third place was Tom Halvorson and Gage Halvorson with 4 fish for 14.00 lbs.  Fourth place was Corey Heinrich and Jerry Heinrich with 4 fish for 11.79 lbs.  Fifth place was Corey Reiffenberger and Lainey Reiffenberger with 3 fish for 9.56 lbs.  Next week will be the final week of fishing league.

