​​ ​', 4);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (2, 6, 'Week 6', '', 'The sixth week of fishing league saw 21 walleyes brought to the scale for 48.82 lbs.  Taking top honors was Jack Anderson and Tony Meseck weighing in 1 fish for  10.56 lbs.  They also had the big fish of the night.  Second place went to Austin Hiepler and Bob Hoium with 1 fish for 5.52 lbs.  Third place was Logan Spray and Mikkal Erickson with 3 fish for 5.32 lbs.  Fourth place was Tom Halvorson and Gage Halvorson with 2 fish for 4.76 lbs.  Fifth place was Garrett Suchanek and Zach Suchanek with 2 fish for 4.54 lbs.', 5);
