INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (3, 4, 'Week 4', '', 'The fourth week of fishing league saw 40 walleyes brought to the scale for 96.15 lbs.  Taking top honors was Bob Hoium and Austin Hiepler weighing in 4 fish for 14.03 lbs.   Second place went to Logan Spray and Mikkal Erickson with 4 fish f0r 11.73 lbs.  Third place was Tom Halvorson and Gage Halvorson with 1 fish for 9.33 lbs.  They also had the big fish of the night a 9.33 lber.  Fourth place was Corey Joyce and (sub) Jeff Reuss with 5 fish for 7.70 lbs.  Fifth place was Sedrick Borsgard and Ryan Anderson with 2 fish for 6.76 lbs.  They also caught a sheepshead that tipped the scales at over 28.4 lbs!', 3);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (3, 5, 'Week 5', '', 'The fifth week of fishing league saw 32 walleyes brought to the scale for 63.97 lbs.  Taking top honors was Tom Ludvigson and Dustin Fernholz weighing in 5 fish for 13.64 lbs.   They also had the big fish of the night a 5.89 lber.  Second place went to Dave Cornelius and Steffan Sticklestad with 5 fish f0r 7.31 lbs.  Third place was Jack Anderson and Tony Meseck with 3 fish for 6.05 lbs.  Fourth place was Matt Fischer and Jeff Rieke with 2 fish for  5.46 lbs.  Fifth place was Eric Spray and Adam Spray with 4 fish for 5.02 lbs.

