INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (4, 2, 'Week 2', '', 'The second week of fishing saw 34 walleyes brought to the scale for 112.625 lbs.  First place was Jamie Jahn and sub Jordan Jahn weighing in 3 fish for 17.1875 lbs.  They also had the big fish of the night, a 10.25 lb walleye.  Second place went to Gage Halvorson and sub Larry Halvorson with 4 fish for 15.25 lbs.  Third place was Dylan Hiepler and Sam Kaderlik with 1 fish for 8.75 lbs.  Fourth place was Corey Reiffenberger and Lainey Reiffenberger with 2 fish for 7.625 lbs.   Fifth place went to Tony Malmquist and Jordan Fischer with 1 fish for 7.5 lbs.  Sixth place was Austin Hiepler and sub Chad Hiepler weighing 3 fish for 7.25 lbs.

