​

​', 2);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (4, 4, 'Week 4', '', 'The fourth week of fishing brought 47 walleyes brought to the scale for 88 lbs.  First place was Austin Hiepler and Bob Hoium weighing in 5 fish for 10.3125 lbs.  They also had the big fish of the night, a 3.625 lb walleye.  Second place went to Dylan Hiepler and Sam Kaderlik with 5 fish for 8.5 lbs.  Third place was Josh Weckwerth and Trent Weckwerth with 5 fish for 8.4375 lbs.  Fourth place was Tom Halvorson and Gage Halvorson with 5 fish for 8.125 lbs.   Fifth place went to Corey Joyce and (sub) Dylan Lines with 3 fish for 7.625 lbs.  Sixth place was Trent Jorgenson and Matt Norby weighing 1 fish for 2.5625 lbs.', 3);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (4, 5, 'Week 5', '', 'The fifth week of fishing brought 3 walleyes brought to the scale for 6.0625 lbs.  First place was Mikkal Erickson and Logan Spray weighing in  1 fish for  3.1875 lbs.  Second place went to Eric Spray and Adam Spray with 2 fish 2.875lbs.  They also had big fish of the night a 1.13 lb walleye.

