INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (4, 6, 'Week 6', '', 'The sixth week of fishing brought 9 walleyes brought to the scale for  18 lbs.  First place was  Jon Jerve and Tony Omacht weighing in 4 fish for  6.5 lbs.   Second place went to Tom Halvorson and Gage Halvorson with 3  fish for  6.1875 lbs. They also had big fish of the night a 3.875 lber.  Third place was Tom Ludvigson and Dustin Fernholz with 1  fish for 2.6875 lbs.  Fourth place was  Dane Prestholdt and Adam Moen with 1 fish for 2.625  lbs.  Next week is the final week of the 2023 fishing league.

​', 5);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (4, 7, 'Week 7', '', 'The final week of fishing league saw 17 walleyes brought to the scale for 47.625 lbs.  First place was  Eric Spray and  Adam Spray weighing in 3 fish for  11.375 lbs.  They also had the big fish of the night a 7.125 lber.  Second place went to  Dave Cornelius and  Brian Krutchek with 4 fish for 10.125 lbs.  Third place was  Mikkal Erickson and  Logan Spray with 2 fish for 4.9375 lbs. Fourth place was Corey Reiffenberger and Lainey Reiffenberger with 1  fish for  4.625 lbs.   Fifth place went to  Tom Ludvigson and Dustin Fernholz  with 2 fish for 4.3125 lbs.  Rounding out the top 6 was Jack Anderson and Tony Meseck weighing 1 fish for 4.0 lbs.

**​', 6);
