INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (5, 1, 'Week 1', '', 'The first week of fishing saw 41 walleyes brought to the scale for 137.675 lbs.  Taking top honors was David Cornelius and Brian Krutchek weighing in 3 fish for 15.875 lbs.  Second place went to Steve Dahle and Jamie Jahn with 5 fish for 15.125lbs.  Third place was Logan Spray and Mikkal Erickson with 5 fish for 14.5625 lbs.  Fourth place was a tie between Corey Reifenberger and (Sub) Brian Hanson with 4 fish for 14.1875 lbs and Tom Halvorson and Gage Halvorson with 5 fish for 14.1875 lbs.  Fifth place was also a tie between Eric Spray and Adam Spray with 5 fish for 14.0625 lbs and Tony Malmquist and Jordan Fischer with 5 fish for 14.0625 lbs.  Sixth Place went to Dylan Hiepler and Sam Kaderlik with 2 fish for 12.3125 lbs.  They also had the big fish of the night, a 8.5 pounder.', 0);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (5, 2, 'Week 2', '', 'The second week of fishing saw 22 walleyes brought to the scale for 87.375 lbs.  First place was Josh and Trent Weckwerth weighing in 2 fish for 14.5625 lbs.  Second place went to Steve Dahle and Jamie Jahn with 2 fish for 10.8125lbs.  Third place was Corey Heinrich and Justin Heinrich with 3 fish for 9.25 lbs.  Fourth place was Tom and Gage Halvorson with 1 fish for 8.25 lbs. They also had the big fish of the night.  Fifth place went to Eric Spray and Adam Spray with 2 fish for 8.0625 lbs.  Sixth place was Tom Ludvigson and Dustin Fernholz weighing 4 fish for 7.75lbs.

​', 1);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (5, 3, 'Week 3', '', 'After cancelling league last week due to weather and previous storm clean-up, the Lac qui Parle Walleye League boats were back at it this week. The third week of fishing saw 16 walleyes brought to the scale for  60.8175 lbs.  First place was Dylan Hiepler and Sam Kaderlik  weighing in  2  fish for  15.5  lbs.  They also had the big fish of the night an 8.625 lber. Second place went to Tom and Gage Halvorson with 2  fish for  11.062  lbs.  Third place was Tom Ludvigson and Dustin Fernholz with 2 fish for 7.8125  lbs.  Fourth place was Tony Malmquist and Jordan Fischer with 1 fish for 6.3125  lbs.   Fifth place went to Steve Dahle and Jamie Jahn with 2  fish for 5.0625 lbs.  Sixth place was  Corey and Laney Reiffenberger weighing 1 fish for  3.5625  lbs.

​

​', 2);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (5, 4, 'Week 4', '', 'The fourth week of fishing league saw 22 walleyes brought to the scale for  66.3125lbs.  First place was Tony Malmquist and Jordan Fischer weighing in 2 fish for  13.4375  lbs.  They also had the big fish of the night an 8.5 lber.  Second place went to Josh and Trent Weckwerth with 2  fish for  13.1875  lbs.  Third place was Dylan Hiepler and Sam Kaderlik with 2 fish for 9.75  lbs.  Fourth place was Pete McGinty and Shannon Larson with 2 fish for 5.125  lbs.   Fifth place went to Eric Spray and Adam Spray with 3 fish for 4.875 lbs.  Sixth place was  Tom Halvorson and Gage Halvorson weighing 2 fish for  4.1875  lbs.', 3);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (5, 5, 'Week 5', '', 'The fifth week of fishing league proved to be a tough bite for most teams, with only 9 walleyes brought to the scale for 27.875 lbs.  First place was Josh and Trent Weckwerth with 2 fish for 12.625 lbs, they also had the the big fish of the night a 6.75 lber.  Second place went to Eric Spray and Adam Spray who weighed 4 fish for 8.6875 lbs.  Third Place was Jack Anderson and Tony Meseck with 2 fish for 4.8125 lbs.  Fourth Place went to Tom Halvorson and Gage Halvorson with 1 fish for 1.75 lbs.**

​​ ​', 4);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (5, 6, 'Week 6', '', 'The sixth week of fishing league saw 6 walleyes brought to the scale for 10.4375 lbs.  First place was Corey and Lacey Reifenberger weighing in 2 fish for 3.5 lbs.  Second place went to Sam Thomas and Scott Van Overbeke with 1  fish for  3.4375  lbs.  Third place was Tom Halvorson and Gage Halvorson with 1 fish for 1.875 lbs.  They also had the big fish of the night a 1.875 lber, due to having the biggest fish by someone in the big fish pot. Fourth place was Pete McGinty and Shannon Larson with 1 fish for 1.625 lbs.   Fifth place went to Dylan Hiepler and Sam Kaderlik with 1 fish for 1.5625 lbs.  Next week will be the last week of fishing league.

**​', 5);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (5, 7, 'Week 7', '', 'The final week of fishing league saw 12 walleyes brought to the scale for 38.375 lbs.  First place was Dave Cornelius and Brian Krutchek weighing in 2 fish for 8.625 lbs.  They also had the big fish of the night a 6.0625 lber.  Second place went to Jack Anderson and Tony Meseck with 2  fish for 8.3125 lbs.  Third place was Jeff Baker and Nick Baker with 1 fish for 7.0625lbs. Fourth place was Pete McGinty and Shannon Larson with 2 fish for 4.875 lbs.   Fifth place went to Cody Enger and Sean Hauck with 1 fish for 3.625lbs.  Rounding out the top 6 was Tony Malmquist and Jordan Fischer who weighed 1 fish for 2.3125 lbs.

**​', 6);
