INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (11, 4, 'Week 4', '', 'There were 39 walleyes caught during weej #4 for 86.6875lbs.  Big fish of the night was caught by Weber/Ruth with a 5.13 lb walleye.  Weber/Ruth took first place with 12.5 lbs.  Second Place went to Spray/Spray with 12.25 lbs.  McGinty/Miller took third place with 9.375 lbs.  Fourth place went to Jerve/Omacht with 7.3125 lbs.  Fifth place was Dahle/Jahn with 6.875 lbs.  Sixth place went to Weckwerth/Stone with 6.875 lbs.

​', 6);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (11, 5, 'Week 5', '', 'It was a tough bite for all the teams and only 10 fish were brought to the scale for a total of 19.375 pounds.  Big fish of the night was caught by Cornelius/Roder, a 2.875 lb walleye.  Jorgenson/Schuler took first place with 4.875 lbs.  Second place went to Cornelius/Roder with 2.875 lbs.  Third place was Enger/Hauck with 2.5625 lbs.  Fourth place was Jerve/Omacht with 2.125 lbs.  Fifth place was Dahle/Jahn with 2.0625 lbs.  Sixth place went to Ludvigson/Zupan with 1.9375 lbs.', 7);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (11, 6, 'Week 6', '', 'Another tough week of fishing, with only 6 walleye weighed in.  Big Fish of the night was a 6.6875 lb walleye caught by Halvorson/Halvorson, but they were not in the big fish pot.  So, Joyce/Larson took the big fish money with a 3.125 lb walleye.  First place went to Halvorson/Halvorson with 6.6875 lbs.  Second place was Zupan/Ludvigson with 3.9375 lbs.  Third place was Joyce/Larson with 3.125 lbs.  Fourth place was Spray/Spray with 1.875 lbs.  Fifth place went to Dahle/Jahn with 1.4375 lbs. Rounding out the top 6 was Pringle/Olson with 1.375 lbs.  Next week will be the final week of fishing league.', 8);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (11, 7, 'Week 7', '', 'League was cancelled due to the weather and will not be made up.  This years league champions were Eric and Adam Spray.  Second place was Steve Dahle and Jamie Jahn.  Third place was Josh Weckwerth and Dustin Stone.

​

![Picture](/images/tournaments/img-3131_orig.jpg)

L to R: Jamie Jahn, Steve Dahle, Eric Spray, Adam Spray, Josh Weckwerth and Dustin Stone.

