INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (13, 1, 'Week 1', '5/13/14', 'Cold front conditions and a 20 mph NW wind had the water looking like chocolate milk.  15 teams hit the water and "0" fish were caught.  Hoping next week will be better!', 0);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (13, 2, 'Week 2', '5/20/14', '', 1);
