INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (13, 5, 'Week 5', '6/10/14', 'The fishing continues to improve on the lake.  Water is  at a very high level right now.  49 walleyes were brought to the scales during this week''s action.  Eric and Adam Spray continued to dominate the field of teams with another first place basket weighing 12.25 pounds.  Jamie Jahn and Steve Dahle put together a 4 fish basket weighing 11.4375 pounds and weighed the big fish of the night again with a 6.8 pounder.  Third place went to Jack Anderson and Corey Reiffenberger who weighed 8.375 pounds.  Rounding out the top 4 was Brent Zupan and Tom Ludvigson with 7.0625 pounds.', 7);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (13, 5, 'Week 5', '6/10/14', '', 8);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (13, 6, 'Week 6', '6/17/14', 'The water on the lake continues to rise and teams had to choose once again if they would fish the North end of the lake or the South end of the lake as boats could not travel under the Milan Bridge.  Jeri Ruth and Kelvin Weber took top honors bringing 4 fish to the scales weighing 13.56 lbs, which included the big fish of the night, a 8.1 pounder.  Second place went to Chad Strei and Brian Devorak who brought 5 fish to the scale weighing 9.5 lbs.  Third Place went to league leaders Eric and Adam Spray who continue to put fish in the boat with  5 fish weighing 9 lbs.  Fourth place once again was Brent Zupan and Tom Ludvigson who weighed 1 fish for 5 lbs.', 9);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (13, 7, 'Week 7', '6/24/14', 'Only 15 fish were caught this week.  First place went to Dave Cornelius and Jim Roth who weighed 3 fish for 6.25 pounds.  Second place finishers were Jeri Ruth and Kelvin Weber who weighed 1 fish for 5.25 pounds, which also won big fish honors for the night.  Third place went to Zach Jorgenson and Trent Jorgenson who weighed 2 fish for 5.125 pounds.  Rounding out the top 4 was Brent Zupan and Tom Ludvigson who weighed 2 fish for 4.0625 pounds.  Next week is the final week of the 2014 fishing league.', 10);
INSERT INTO league_weeks (league_id, week_number, title, date, content, sort_order) VALUES (13, 8, 'Week 8', '7/8/14', '7  fish were caught this week.  First place went to Tom Ludvigson and Brent Zupan with 7.0625 pounds.  Second place finishers were Chad Strei and Brian Devorak who weighed 1 fish for 2.375 pounds Third place went to Steve Dahle and Jamie Jahn who weighed 1 fish for 2.125 pounds.  Rounding out the top 4 was Zach Jorgenson and Trent Jorgenson who weighed 1 fish for 1.9375 pounds.

2014 Lac Qui Parle Lake Walleye League Top 3 Teams

3rd Place:  Tom Ludvigson and Brent Zupan

2nd Place:  Jeri Ruth and Kelvin Weber

1st Place:  Adam Spray and Eric Spray

